    border-radius: 8px;
    font-size: 1rem;
    cursor: pointer;
    transition: background 0.2s;
}

button:hover {
    background: #4338ca;
}

#output {
    margin-top: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
    min-height: 60px;
    text-align: left;
    font-family: monospace;
    white-space: pre-wrap;
    word-break: break-word;
}

footer {
    margin-top: 2rem;
    font-size: 0.8rem;
    color: #999;
}

